	// where 'state' indicates the nature of the last transition.
	// State 0: The sequence ends with a 'less than' transition (..., > nums[i]) or is of length 1.
	// State 1: The sequence ends with a 'greater than' transition (..., < nums[i]).
	// Note: The definition of state needs to align with the alternating pattern.

	// Let's redefine states based on the comparison between the element at i and the previous element:
	// dp[i][0]: Max score ending at nums[i], where nums[i] is GREATER than the previous element (Up move: ... < nums[i])
	// dp[i][1]: Max score ending at nums[i], where nums[i] is SMALLER than the previous element (Down move: ... > nums[i])

	// Since length 1 subsequences are valid, they can start in either state implicitly,
	// but we initialize based on the value itself.

	// dp[i][0]: Max score ending at nums[i] with an UP movement (i.e., previous < nums[i])
	// dp[i][1]: Max score ending at nums[i] with a DOWN movement (i.e., previous > nums[i])
	dp := make([][2]int64, n)

	maxScore := int64(0)

	for i := 0; i < n; i++ {
		currentVal := nums[i]

		// Base case: Subsequence of length 1
		dp[i][0] = currentVal
		dp[i][1] = currentVal

		for j := 0; j < i; j++ {
			// Check distance condition
			if int64(i-j) >= k {
				prevVal := nums[j]

				// Case 1: Current move is UP (nums[j] < nums[i]). State transition to dp[i][0].
				// The previous state at j must have been a DOWN move (dp[j][1]) or length 1 (which is covered by initialization, but we check for continuation).
				// If dp[j][1] represents a sequence ending in a DOWN move (... > nums[j]), then nums[j] < nums[i] makes it ... > nums[j] < nums[i] (Valid alternating).
				if prevVal < currentVal {
					// We can extend a sequence ending in a DOWN move at j (dp[j][1])
					dp[i][0] = max(dp[i][0], dp[j][1]+currentVal)

					// We can also start a new sequence of length 2: nums[j] < nums[i]
					// This is covered by the initial dp[i][0] = currentVal if we consider the transition from a hypothetical zero-score predecessor,
					// but since dp[j][1] already includes nums[j], dp[j][1]+currentVal is the correct way to extend.
				}

				// Case 2: Current move is DOWN (nums[j] > nums[i]). State transition to dp[i][1].
				// The previous state at j must have been an UP move (dp[j][0]) or length 1.
				// If dp[j][0] represents a sequence ending in an UP move (... < nums[j]), then nums[j] > nums[i] makes it ... < nums[j] > nums[i] (Valid alternating).
				if prevVal > currentVal {
					// We can extend a sequence ending in an UP move at j (dp[j][0])
					dp[i][1] = max(dp[i][1], dp[j][0]+currentVal)
				}
			}
		}

		// Update overall maximum score
		maxScore = max(maxScore, dp[i][0])
		maxScore = max(maxScore, dp[i][1])
	}

	return maxScore
}

func max(a, b int64) int64 {
	if a > b {
		return a
	}
	return b
}
