// solve calculates the maximum score of a valid alternating subsequence.
func solve(nums []int64, k int64) int64 {
	n := len(nums)
	if n == 0 {
		return 0
	}

	// dp_less[i]: maximum score of a valid alternating subsequence ending at index i,
	// where the last transition was an "less than" (<) (i.e., nums[i-1] < nums[i]).
	// The subsequence must look like: ... > nums[i] (if it has length >= 2)
	// or length 1.
	dp_less := make([]int64, n)

	// dp_greater[i]: maximum score of a valid alternating subsequence ending at index i,
	// where the last transition was a "greater than" (>) (i.e., nums[i-1] > nums[i]).
	// The subsequence must look like: ... < nums[i] (if it has length >= 2)
	// or length 1.
	dp_greater := make([]int64, n)

	maxScore := int64(0)

	for i := 0; i < n; i++ {
		// Base case: A subsequence of length 1 ending at i always has a score of nums[i].
		dp_less[i] = nums[i]
		dp_greater[i] = nums[i]

		// Iterate over all possible previous elements j
		for j := 0; j < i; j++ {
			// Check the distance condition: i - j >= k
			if int64(i-j) < k {
				continue
			}

			// 1. Calculate dp_less[i] (ending with nums[i] where the sequence is ... > nums[i])
			// This means the previous element nums[j] must satisfy nums[j] > nums[i].
			// The previous sequence ending at j must have been one that ended with a "greater than" transition,
			// or it was a length 1 sequence (which is covered by the initialization, but we need to check the alternating condition).
			if nums[j] > nums[i] {
				// If the sequence ending at j was a '<' ending (dp_less[j]), then adding nums[i] makes it ... < nums[j] > nums[i], which is valid.
				// If the sequence ending at j was a '>' ending (dp_greater[j]), then adding nums[i] makes it ... > nums[j] > nums[i], which violates the alternating condition (unless length was 1 at j).
				// However, the structure of dp_less/dp_greater is defined by the *last* transition.
				// If we transition from j to i with nums[j] > nums[i], the new state is "greater than" transition ending at i.
				// Wait, the definition needs care:
				// dp_less[i]: Subsequence ends with X < nums[i]. Predecessor j must have nums[j] < nums[i]. Previous state must have been > transition ending at j.
				// dp_greater[i]: Subsequence ends with X > nums[i]. Predecessor j must have nums[j] > nums[i]. Previous state must have been < transition ending at j.

				// Let's redefine:
				// dp_up[i]: Max score ending at i, where nums[i] > nums[j] (last move was UP/increasing).
				// dp_down[i]: Max score ending at i, where nums[i] < nums[j] (last move was DOWN/decreasing).

				// Initialize dp_up[i] = nums[i], dp_down[i] = nums[i] for length 1 sequence.

				// Case 1: Transition j -> i is UP (nums[i] > nums[j]). New state is dp_up[i].
				// The sequence ending at j must have ended with a DOWN transition (nums[j] < nums[k] for some k before j, or length 1).
				if nums[i] > nums[j] {
					// If we append nums[i] to a sequence ending at j (where j was the second to last element),
					// the transition j->i is increasing (UP).
					// The sequence ending at j must have been one that ended with a DOWN transition (dp_down[j]),
					// OR it was a sequence of length 1 (dp_down[j] initialized to nums[j]).
					dp_up[i] = max(dp_up[i], dp_down[j] + nums[i])
				}

